import React from "react";
import { StyleSheet, Text, View } from "react-native";

type Props = {
  theme: any;
};

export function ProfileCard({ theme }: Props) {
  return (
    <View
      style={[
        styles.card,
        {
          backgroundColor: theme.card,
        },
      ]}
    >
      <View style={styles.avatar}>
        <Text style={styles.avatarText}>JD</Text>
      </View>

      <Text
        style={[
          styles.name,
          {
            color: theme.text,
          },
        ]}
      >
        Jan Developer
      </Text>

      <Text
        style={[
          styles.description,
          {
            color: theme.secondaryText,
          },
        ]}
      >
        React Native Developer
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  card: {
    borderRadius: 20,
    padding: 20,
    alignItems: "center",
    marginBottom: 24,
  },

  avatar: {
    width: 80,
    height: 80,
    borderRadius: 40,
    backgroundColor: "#4a67ff",
    justifyContent: "center",
    alignItems: "center",
    marginBottom: 12,
  },

  avatarText: {
    color: "#fff",
    fontSize: 28,
    fontWeight: "700",
  },

  name: {
    fontSize: 22,
    fontWeight: "700",
  },

  description: {
    marginTop: 6,
    fontSize: 15,
  },
});
